// game-of-life.spec.ts
import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  it("should kill a single live cell (underpopulation: 0 neighbors)", () => {
    expect(nextGeneration([[0, 0]])).toEqual([]);
  });
  it("should kill two adjacent live cells (underpopulation: 1 neighbor each)", () => {
    expect(
      nextGeneration([
        [0, 1],
        [1, 1],
      ]),
    ).toEqual([]);
  });
  it("should keep a live cell with 3 live neighbors alive (survival)", () => {
    const result = nextGeneration([
      [0, 0],
      [1, 0],
      [2, 0],
      [1, 1],
    ]);
    expect(result.sort()).toEqual([
      [1, 0],
      [1, 1],
    ]);
  });
  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
  it.todo("should bring a dead cell with exactly 3 live neighbors to life (reproduction)");
  it.todo("should keep a block still life unchanged");
  it.todo("should oscillate a vertical blinker to a horizontal blinker (negative coordinates)");
});
